import json
from typing import Dict, Optional

def classify_waste(item_name: str) -> Dict[str, Optional[str]]:
    """
    Classifies a waste item into one of the six Polish recycling bins.
    Returns a dictionary with the bin color, category, and notes.
    """
    item_lower = item_name.lower()
    classification = {
        "bin_color": None,
        "bin_category": None,
        "notes": None,
        "preparation": None
    }

    # Define classification rules
    if any(word in item_lower for word in ["plastic", "bottle", "can", "drink"]):
        classification.update({
            "bin_color": "🟡",
            "bin_category": "PLASTIC/METAL",
            "notes": "Rinse before disposal if possible.",
            "preparation": "Remove caps and labels if they are not recyclable."
        })
    elif any(word in item_lower for word in ["paper", "cardboard", "box", "newspaper"]):
        classification.update({
            "bin_color": "🔵",
            "bin_category": "PAPER",
            "notes": "Remove plastic linings or contaminants.",
            "preparation": "Flatten cardboard boxes to save space."
        })
    elif any(word in item_lower for word in ["glass", "jar", "bottle"]):
        classification.update({
            "bin_color": "🟢",
            "bin_category": "GLASS",
            "notes": "Remove lids and caps (plastic/metal goes to yellow bin).",
            "preparation": "Rinse to remove residues."
        })
    elif any(word in item_lower for word in ["food", "scrap", "garden", "plant", "fruit"]):
        classification.update({
            "bin_color": "🟤",
            "bin_category": "BIO",
            "notes": "Only organic waste allowed.",
            "preparation": "Chop large items to speed up decomposition."
        })
    elif any(word in item_lower for word in ["mug", "mirror", "ceramic", "pizza box", "grease", "blister pack", "pills", "coffee cup"]):
        classification.update({
            "bin_color": "⚫",
            "bin_category": "MIXED",
            "notes": "Avoid placing items here unless they are truly contaminated or composite.",
            "preparation": "None required; dispose as-is."
        })
    elif any(word in item_lower for word in ["clothes", "shoe", "textile"]):
        classification.update({
            "bin_color": "🟣",
            "bin_category": "TEXTILE",
            "notes": "Separate collection is mandatory since January 2026.",
            "preparation": "Bundle clothes to prevent littering."
        })
    else:
        classification.update({
            "bin_color": None,
            "bin_category": "UNKNOWN",
            "notes": "Consult local guidelines or the app for clarification.",
            "preparation": None
        })

    return classification

# Example usage:
print(classify_waste("Pizza box with grease"))
print(classify_waste("Old mirror"))
print(classify_waste("Plastic water bottle"))
